SELECT COUNT(DISTINCT material_id) 
FROM access_logs 
WHERE user_id = 1;

SELECT *
FROM materials
ORDER BY manufacturing_date ASC;

SELECT DISTINCT u.user_id, u.user_name
FROM users u
JOIN material_history mh ON u.user_id = mh.user_id;

SELECT COUNT(*)
FROM materials
WHERE condition = (SELECT condition_id FROM material_conditions WHERE condition_name = 'Annealed');
